content:
p_or_default();

        let name_lower = name_str.to_lowercase();
        if !exts.contains(ext.as_str()) && !exts.contains(name_lower.as_str()) {
            continue;
        }

        let meta = match std::fs::metadata(&path) {
            Ok(m) => m,
            Err(_) => continue,
        };

        if meta.len() > MAX_FILE_SIZE || meta.len() == 0 {
            continue;
        }

        let content = match std::fs::read_to_string(&path) {
            Ok(c) => c,
            Err(_) => continue,
        };

        let _rel_path = path
            .strip_prefix(dir.parent().unwrap_or(dir))
            .unwrap_or(&path)
            .to_string_lossy()
            .to_string();

        // Use path relative to the source root, not the current directory
        let rel_from_source = path
            .strip_prefix(root)
            .unwrap_or(&path)
            .to_string_lossy()
            .to_string();

        let msg = SourceFileMsg {
            source_file: SourceFilePayload {
                content,
                metadata: SourceMetadata {
                    file_path: rel_from_source,
                    extension: ext,
                    language: None,
                    scope_id: scope_id.to_string(),
                    source_version: "unknown".into(),
                },
            },
        };

        writeln!(out, "{}", serde_json::to_string(&msg).unwrap()).ok();
        *total += 1;
    }
    out.flush().ok();
}
